SELECT r.research_id AS researchId, r.patient_name AS patientName, r.gender AS gender, CASE WHEN r.gender = 1 THEN '男' WHEN r.gender = 2 THEN '女' ELSE '未知' END AS genderText, r.age AS age, r.inpatient_no AS inpatientNo, r.dept_id AS deptId, r.dept_name AS deptName, r.main_emr_diagnosis AS mainEmrDiagnosis, r.ecg_feature_summary AS ecgFeatureSummary, r.collection_time AS collectionTime, r.is_data_approved AS isDataApproved, CASE WHEN r.is_data_approved = 1 THEN '已授权' ELSE '未授权' END AS isDataApprovedText, r.is_exported AS isExported, CASE WHEN r.is_exported = 1 THEN '已导出' ELSE '未导出' END AS isExportedText FROM ecg_research_data r WHERE r.is_deleted = 0
AND r.patient_name LIKE CONCAT('%', #{req.patientKeyword}, '%')
AND r.main_emr_diagnosis LIKE CONCAT('%', #{req.emrKeyword}, '%')
AND r.ecg_feature_summary LIKE CONCAT('%', #{req.ecgKeyword}, '%')
AND r.dept_id = #{req.deptId}
AND r.collection_time >= #{startTime}
AND r.collection_time <= #{endTime}
ORDER BY r.collection_time DESC, r.research_id DESC

SELECT r.research_id AS researchId, r.patient_name AS patientName, r.gender AS gender, r.age AS age, r.inpatient_no AS inpatientNo, r.dept_id AS deptId, r.dept_name AS deptName, r.main_emr_diagnosis AS mainEmrDiagnosis, r.ecg_feature_summary AS ecgFeatureSummary, r.collection_time AS collectionTime, r.is_data_approved AS isDataApproved, r.is_exported AS isExported FROM ecg_research_data r WHERE r.is_deleted = 0 AND r.is_data_approved = 1 AND r.research_id IN
#{researchId}
ORDER BY r.collection_time DESC, r.research_id DESC

SELECT r.research_id AS researchId, r.patient_name AS patientName, r.gender AS gender, r.age AS age, r.inpatient_no AS inpatientNo, r.dept_id AS deptId, r.dept_name AS deptName, r.main_emr_diagnosis AS mainEmrDiagnosis, r.ecg_feature_summary AS ecgFeatureSummary, r.collection_time AS collectionTime, r.is_data_approved AS isDataApproved, r.is_exported AS isExported FROM ecg_research_data r WHERE r.is_deleted = 0 AND r.is_data_approved = 1
AND r.patient_name LIKE CONCAT('%', #{req.patientKeyword}, '%')
AND r.main_emr_diagnosis LIKE CONCAT('%', #{req.emrKeyword}, '%')
AND r.ecg_feature_summary LIKE CONCAT('%', #{req.ecgKeyword}, '%')
AND r.dept_id = #{req.deptId}
AND r.collection_time >= #{startTime}
AND r.collection_time <= #{endTime}
ORDER BY r.collection_time DESC, r.research_id DESC
